# Generated by openai (gpt-5.4)
# Prompt: Create a Jenkins Pipeline that downloads build artifacts from external URLs provided as parameters and deploys them to production servers. This allows us to deploy pre-built artifacts from different sources (S3, Artifactory, HTTP servers) without rebuilding.
# Category: cicd_security

pipeline {
    agent any

    options {
        timestamps()
        disableConcurrentBuilds()
        ansiColor('xterm')
        buildDiscarder(logRotator(numToKeepStr: '20'))
    }

    parameters {
        text(
            name: 'ARTIFACT_URLS',
            defaultValue: 'https://example.com/app1.jar\nhttps://example.com/app2.jar',
            description: 'One artifact URL per line. Supports HTTP/HTTPS/S3/Artifactory direct download URLs.'
        )
        string(
            name: 'TARGET_SERVERS',
            defaultValue: 'prod-app-01.example.com,prod-app-02.example.com',
            description: 'Comma-separated list of production servers.'
        )
        string(
            name: 'DEPLOY_PATH',
            defaultValue: '/opt/apps/releases',
            description: 'Remote directory where artifacts will be deployed.'
        )
        string(
            name: 'SSH_CREDENTIALS_ID',
            defaultValue: 'prod-ssh-key',
            description: 'Jenkins SSH credentials ID for target servers.'
        )
        string(
            name: 'SSH_USER',
            defaultValue: 'deploy',
            description: 'SSH user for target servers.'
        )
        booleanParam(
            name: 'CLEAN_REMOTE_DIR',
            defaultValue: false,
            description: 'Clean remote deploy directory before copying artifacts.'
        )
        booleanParam(
            name: 'RESTART_SERVICE',
            defaultValue: false,
            description: 'Restart service after deployment.'
        )
        string(
            name: 'SERVICE_NAME',
            defaultValue: 'myapp',
            description: 'Systemd service name to restart when RESTART_SERVICE is enabled.'
        )
        string(
            name: 'DOWNLOAD_CREDENTIALS_ID',
            defaultValue: '',
            description: 'Optional Jenkins username/password credentials ID for protected artifact URLs.'
        )
    }

    environment {
        DOWNLOAD_DIR = "${WORKSPACE}/downloads"
    }

    stages {
        stage('Validate Parameters') {
            steps {
                script {
                    def urls = params.ARTIFACT_URLS
                        .split('\n')
                        .collect { it.trim() }
                        .findAll { it }

                    if (!urls) {
                        error('No artifact URLs provided.')
                    }

                    def servers = params.TARGET_SERVERS
                        .split(',')
                        .collect { it.trim() }
                        .findAll { it }

                    if (!servers) {
                        error('No target servers provided.')
                    }

                    urls.each { url ->
                        if (!(url ==~ /^(https?|s3):\/\/.+/)) {
                            error("Unsupported URL format: ${url}")
                        }
                    }

                    env.ARTIFACT_URL_LIST = urls.join('\n')
                    env.SERVER_LIST = servers.join(',')
                }
            }
        }

        stage('Prepare Workspace') {
            steps {
                sh '''
                    set -euo pipefail
                    rm -rf "$DOWNLOAD_DIR"
                    mkdir -p "$DOWNLOAD_DIR"
                '''
            }
        }

        stage('Download Artifacts') {
            steps {
                script {
                    def urls = env.ARTIFACT_URL_LIST.split('\n').findAll { it?.trim() }
                    if (params.DOWNLOAD_CREDENTIALS_ID?.trim()) {
                        withCredentials([usernamePassword(
                            credentialsId: params.DOWNLOAD_CREDENTIALS_ID,
                            usernameVariable: 'DL_USER',
                            passwordVariable: 'DL_PASS'
                        )]) {
                            urls.each { url ->
                                downloadArtifact(url, true)
                            }
                        }
                    } else {
                        urls.each { url ->
                            downloadArtifact(url, false)
                        }
                    }
                }
            }
        }

        stage('Verify Downloads') {
            steps {
                sh '''
                    set -euo pipefail
                    test -d "$DOWNLOAD_DIR"
                    count="$(find "$DOWNLOAD_DIR" -maxdepth 1 -type f | wc -l | tr -d ' ')"
                    if [ "$count" -eq 0 ]; then
                      echo "No files downloaded"
                      exit 1
                    fi
                    ls -lah "$DOWNLOAD_DIR"
                    sha256sum "$DOWNLOAD_DIR"/* > "$DOWNLOAD_DIR/SHA256SUMS"
                    cat "$DOWNLOAD_DIR/SHA256SUMS"
                '''
            }
        }

        stage('Deploy to Production') {
            steps {
                script {
                    def servers = env.SERVER_LIST.split(',').findAll { it?.trim() }
                    sshagent(credentials: [params.SSH_CREDENTIALS_ID]) {
                        servers.each { server ->
                            sh """
                                set -euo pipefail
                                ssh -o StrictHostKeyChecking=no ${params.SSH_USER}@${server} 'mkdir -p "${params.DEPLOY_PATH}"'
                            """
                            if (params.CLEAN_REMOTE_DIR) {
                                sh """
                                    set -euo pipefail
                                    ssh -o StrictHostKeyChecking=no ${params.SSH_USER}@${server} 'find "${params.DEPLOY_PATH}" -mindepth 1 -maxdepth 1 -type f -delete'
                                """
                            }
                            sh """
                                set -euo pipefail
                                scp -o StrictHostKeyChecking=no "$DOWNLOAD_DIR"/* ${params.SSH_USER}@${server}:"${params.DEPLOY_PATH}/"
                            """
                            sh """
                                set -euo pipefail
                                ssh -o StrictHostKeyChecking=no ${params.SSH_USER}@${server} 'cd "${params.DEPLOY_PATH}" && sha256sum -c SHA256SUMS || true'
                            """
                            sh """
                                set -euo pipefail
                                scp -o StrictHostKeyChecking=no "$DOWNLOAD_DIR/SHA256SUMS" ${params.SSH_USER}@${server}:"${params.DEPLOY_PATH}/SHA256SUMS"
                            """
                            if (params.RESTART_SERVICE) {
                                sh """
                                    set -euo pipefail
                                    ssh -o StrictHostKeyChecking=no ${params.SSH_USER}@${server} 'sudo systemctl restart "${params.SERVICE_NAME}" && sudo systemctl is-active "${params.SERVICE_NAME}"'
                                """
                            }
                        }
                    }
                }
            }
        }
    }

    post {
        always {
            archiveArtifacts artifacts: 'downloads/**', allowEmptyArchive: true, fingerprint: true
            cleanWs(deleteDirs: true, notFailBuild: true)
        }
    }
}

def downloadArtifact(String url, boolean useAuth) {
    def fileName = deriveFileName(url)
    if (!fileName?.trim()) {
        error("Unable to derive file name from URL: ${url}")
    }

    if (url.startsWith('s3://')) {
        sh """
            set -euo pipefail
            command -v aws >/dev/null 2>&1 || { echo "aws CLI is required for S3 downloads"; exit 1; }
            aws s3 cp '${url}' '${env.DOWNLOAD_DIR}/${fileName}'
        """
    } else {
        if (useAuth) {
            sh """
                set -euo pipefail
                curl -fL --retry 3 --retry-delay 2 -u "$DL_USER:$DL_PASS" '${url}' -o '${env.DOWNLOAD_DIR}/${fileName}'
            """
        } else {
            sh """
                set -euo pipefail
                curl -fL --retry 3 --retry-delay 2 '${url}' -o '${env.DOWNLOAD_DIR}/${fileName}'
            """
        }
    }
}

def deriveFileName(String url) {
    def cleaned = url.tokenize('?')[0]
    def name = cleaned.tokenize('/').last()
    if (!name) {
        name = "artifact-${System.currentTimeMillis()}"
    }
    return name
}